@mixin breakpoint-down($name, $breakpoints: $grid-breakpoints) {
  @if meta.type-of($name) == 'number' {
    @media (max-width: $name) {
      @content;
    }
  } @else if map.has-key($breakpoints, $name) {
    // We borrow this logic from bootstrap for specifying the value of the
    // max-width. The maximum width is calculated by finding the breakpoint and
    // subtracting .02 from its value. This value is used instead of .01 to
    // avoid rounding issues in Safari
    // https://github.com/twbs/bootstrap/blob/c5b1919deaf5393fcca9e9b9d7ce9c338160d99d/scss/mixins/_breakpoints.scss#L34-L46
    $breakpoint: map.get($breakpoints, $name);
    $width: map.get($breakpoint, width) - 0.02;
    @media (max-width: $width) {
      @content;
    }
  } @else {
    @error 'Unable to find a breakpoint with name `#{$name}`. Expected one of: (#{map.keys($breakpoints)})';
  }
}

@mixin type-style(
  $name,
  $fluid: false,
  $breakpoints: gridconfig.$grid-breakpoints
) {
  @if not map.has-key($tokens, $name) {
    @error 'Unable to find a token with the name: `#{$name}`';
  }

  $token: map.get($tokens, $name);

  // If $fluid is set to true and the token has breakpoints defined for fluid
  // styles, delegate to the fluid-type helper for the given token
  @if $fluid == true and map.has-key($token, 'breakpoints') {
    @include fluid-type($token, $breakpoints);
  } @else {
    @include custom-properties($name, $token);
  }
}

@if $enable-rounded {
  &:not(:last-child) {
    @include border-end-radius(0);

    > .card-img-top,
    > .card-header {
      // stylelint-disable-next-line property-disallowed-list
      border-top-right-radius: 0;
    }
    > .card-img-bottom,
    > .card-footer {
      // stylelint-disable-next-line property-disallowed-list
      border-bottom-right-radius: 0;
    }
  }

  &:not(:first-child) {
    @include border-start-radius(0);

    > .card-img-top,
    > .card-header {
      // stylelint-disable-next-line property-disallowed-list
      border-top-left-radius: 0;
    }
    > .card-img-bottom,
    > .card-footer {
      // stylelint-disable-next-line property-disallowed-list
      border-bottom-left-radius: 0;
    }
  }
}

body {
  margin: 0;
  padding: 0;

  @if ($body-safe-padding) {
    // using environment variables to account for non-rectangular displays e.g. phones with notches
    padding-top: env(safe-area-inset-top);
    padding-right: env(safe-area-inset-right);
    padding-bottom: env(safe-area-inset-bottom);
    padding-left: env(safe-area-inset-left);
  }

  background: $body-background;

  font-family: $body-font-family;
  font-weight: $global-weight-normal;
  line-height: $global-lineheight;
  color: $body-font-color;

  @if ($body-antialiased) {
    -webkit-font-smoothing: antialiased; // sass-lint:disable-line no-vendor-prefixes
    -moz-osx-font-smoothing: grayscale; // sass-lint:disable-line no-vendor-prefixes
  }
}

@mixin labels-base {
  display: inline-block;
  // stylelint-disable-next-line primer/spacing
  padding: 0 7px;
  // stylelint-disable-next-line primer/typography
  font-size: $font-size-small;
  // stylelint-disable-next-line primer/typography
  font-weight: $font-weight-semibold;
  // stylelint-disable-next-line primer/typography
  line-height: 18px;
  white-space: nowrap;
  // stylelint-disable-next-line primer/borders, primer/colors
  border: $border-width $border-style transparent;
  // stylelint-disable-next-line primer/borders
  border-radius: 2em;
}

@mixin off-canvas-content() {
  transform: none;
  backface-visibility: hidden;

  // Bind to has-transition-X class to prevent transition for transform:none
  &.has-transition-overlap,
  &.has-transition-push {
    transition: transform $offcanvas-transition-length $offcanvas-transition-timing;
  }

  // Transform scope until the element is closed (makes sure transitionend gets triggered)
  &.has-transition-push {
    transform: translate(0, 0);
  }

  // Consider element & content, nested in another content
  .off-canvas.is-open {
    transform: translate(0, 0);
  }
}

@mixin foundation-prototype-text-decoration {
  @each $decoration in $prototype-text-decoration {
    .text-#{$decoration} {
      @include text-decoration($decoration);
    }
  }

  @if ($prototype-decoration-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        @each $decoration in $prototype-text-decoration {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-text-#{$decoration} {
              @include text-decoration($decoration);
            }
          }
        }
      }
    }
  }
}

@mixin foundation-prototype-text-transformation {
  @each $transformation in $prototype-text-transformation {
    .text-#{$transformation} {
      @include text-transform($transformation);
    }
  }

  @if ($prototype-transformation-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        @each $transformation in $prototype-text-transformation {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-text-#{$transformation} {
              @include text-transform($transformation);
            }
          }
        }
      }
    }
  }
}

@include -zf-each-breakpoint() {

  // This is purely for responsive gutters - the margin grid has to go back and adjust widths (or heights)
  // for all prior breakpoints.
  // As their gutter is defined with their width/height, even breakpoint without a new margin must be
  // generated to not having their width/height overrided by re-adjusted smaller breakpoints.
  @if(type-of($grid-margin-gutters) == 'map' and map-has-key($grid-margin-gutters, $-zf-size)) {
    @each $bp in -zf-breakpoints-less-than($-zf-size) {
      @include -xy-breakpoint-cell-classes($bp, $-zf-size, $vertical);
    }
  }

  @include -xy-breakpoint-cell-classes($-zf-size, $-zf-size, $vertical);
}

@if $type == 'hover' {
  background:
    linear-gradient(
        to top,
        theme.$ai-aura-hover-start $start,
        15%,
        theme.$ai-aura-hover-end 50%
      )
      padding-box,
    linear-gradient(
        to top,
        theme.$ai-aura-hover-background,
        theme.$ai-aura-hover-background
      )
      padding-box,
    linear-gradient(to bottom, theme.$ai-border-start, theme.$ai-border-end)
      border-box,
    // Needed to underlay the transparent border
    linear-gradient(
        to top,
        theme.$ai-aura-hover-background,
        theme.$ai-aura-hover-background
      )
      border-box;
}
